mapper.select:


select ${columnName} from ${tableName}
where company_code = #{companycode,jdbcType=VARCHAR}
and DATE_ADD(DATE(TIME),INTERVAL 2 DAY) >= DATE(#{time,jdbcType=TIMESTAMP}) 
and DATE_ADD(DATE(TIME),INTERVAL -2 DAY) <= DATE(#{time,jdbcType=TIMESTAMP}) 
order by time asc



select value,index_code,time from ${tableName}
where index_code = #{iIndexCode,jdbcType=VARCHAR}
and uidentify = #{mark,jdbcType=VARCHAR}
and DATE_ADD(DATE(TIME),INTERVAL 2 DAY) >= DATE(#{sTime,jdbcType=TIMESTAMP}) 
and DATE_ADD(DATE(TIME),INTERVAL -2 DAY) <= DATE(#{eTime,jdbcType=TIMESTAMP}) 
order by time asc



select value,index_code from ${tableName}
where index_code like CONCAT('%',#{indexcode,jdbcType=VARCHAR},'%')
and uidentify = #{mark,jdbcType=VARCHAR}
and DATE_ADD(DATE(TIME),INTERVAL 2 DAY) >= DATE(#{time,jdbcType=TIMESTAMP}) 
and DATE_ADD(DATE(TIME),INTERVAL -2 DAY) <= DATE(#{time,jdbcType=TIMESTAMP})



select value,index_code,time,uidentify from ${tableName}
where index_code = #{iIndexCode,jdbcType=VARCHAR}
and DATE_ADD(DATE(TIME),INTERVAL 2 DAY) >= DATE(#{time,jdbcType=TIMESTAMP}) 
and DATE_ADD(DATE(TIME),INTERVAL -2 DAY) <= DATE(#{time,jdbcType=TIMESTAMP})



select value from ${tableName}
where index_code = #{iIndexCode,jdbcType=VARCHAR}
and uidentify = #{mark,jdbcType=VARCHAR}
and DATE_ADD(DATE(TIME),INTERVAL 2 DAY) >= DATE(#{time,jdbcType=TIMESTAMP}) 
and DATE_ADD(DATE(TIME),INTERVAL -2 DAY) <= DATE(#{time,jdbcType=TIMESTAMP})


        select value,index_code,time,uidentify from ${tableName}
		where  DATE_ADD(DATE(TIME),INTERVAL 2 DAY) >= DATE(#{stime,jdbcType=TIMESTAMP}) 
		and DATE_ADD(DATE(TIME),INTERVAL -2 DAY) <= DATE(#{etime,jdbcType=TIMESTAMP}) 
		limit ${start},${limit}


        select value,index_code,time,uidentify from ${tableName}
		where  DATE(TIME) >= DATE(#{stime,jdbcType=TIMESTAMP}) 
		and DATE(TIME) <= DATE(#{etime,jdbcType=TIMESTAMP}) 
		and uidentify = #{tag,jdbcType=VARCHAR}
		limit ${start},${limit}
